#include <bits/stdc++.h>
using namespace std;
const int maxn=5e6+5;
int nxt[maxn],a[maxn],b[maxn];
int da[maxn*2],db[maxn*2],ans=-1;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n;
	cin>>n;
	if(n==1) {
		cout<<0;
		return 0;
	}
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	for(int i=1; i<=n; i++) {
		cin>>b[i];
	}
	for(int i=1; i<n; i++) {
		da[i]=a[i+1]-a[i];
		db[i]=b[i+1]-b[i];
	}
	da[n]=a[1]-a[n];
	db[n]=b[1]-b[n];
	for(int i=1; i<=n; i++) {
		da[n+i]=da[i];
	}
	int len=0;
	for(int i=2; i<=n; i++) {
		while(len>0&&db[i]!=db[len+1]) {
			len=nxt[len];
		}
		if(db[i]==db[len+1]) {
			len++;
		}
		nxt[i]=len;
	}
	len=0;
	for(int i=1; i<=2*n; i++) {
		while(len&&da[i]!=db[len+1]) {
			len=nxt[len];
		}
		if(da[i]==db[len+1]) {
			len++;
		}
		if(len==n) {
			ans=i-n;
			break;
		}
	}
	cout<<ans;
	return 0;
}
